  -- Locking
  @fn checkLock()  @ 730
      @contract  writes (add*, delete*, structural assign*) must run inside mm:modify(fn)
      @contract  modify disables sort, runs fn under lock, re-sorts, then reload→callbacks
  -- Notes
  @fn cloneOut(evt)  @ 748
