  @api mm:load(newTake)  @ 320
      @contract  internal reload (lock held) reuses live metadata; skips ext-data read + write
      @contract  external load (take swap, undo, watcher, init) does full loadMetadata + saveMetadata
  @api mm:reload()  @ 714
